foreach ($this->prepareNestedWithRelationships($relations) as $name => $constraints) {
    // We need to separate out any nested includes, which allows the developers
    // to load deep relationships using "dots" without stating each level of
    // the relationship with its own key in the array of eager-load names.
    $results = $this->addNestedWiths($name, $results);

    $results[$name] = $constraints;
}

if ($this->getIncrementing()) {
    $this->insertAndSetId($query, $attributes);
}

// If the table isn't incrementing we'll simply insert these attributes as they
// are. These attribute arrays must contain an "id" column previously placed
// there by the developer as the manually determined key for these models.
else {
    if (empty($attributes)) {
        return true;
    }

    $query->insert($attributes);
}

if ($item->isDir()) {
    $path = $item->getPathname();

    if (! $this->copyDirectory($path, $target, $options)) {
        return false;
    }
}

// If the current items is just a regular file, we will just copy this to the new
// location and keep looping. If for some reason the copy fails we'll bail out
// and return false, so the developer is aware that the copy process failed.
elseif (! $this->copy($item->getPathname(), $target)) {
    return false;
}

if (! $memcached->getServerList()) {
    // For each server in the array, we'll just extract the configuration and add
    // the server to the Memcached connection. Once we have added all of these
    // servers we'll verify the connection is successful and return it back.
    foreach ($servers as $server) {
        $memcached->addServer(
            $server['host'], $server['port'], $server['weight']
        );
    }
}

foreach ($updates as $path => $value) {
    $value = $this->hydrateForUpdate($data, $path, $value, $context);

    // We only want to run "updated" hooks after all properties have
    // been updated so that each individual hook has the ability
    // to overwrite the updated states of other properties...
    $finishes[] = $this->updateProperty($component, $path, $value, $context);
}

if (filled($typedParameterClassName)) {
    // Dependencies are wrapped in an array to differentiate between null and no value.
    $defaultWrappedDependencyByType = $this->resolveDefaultClosureDependencyForEvaluationByType($typedParameterClassName);

    if (count($defaultWrappedDependencyByType)) {
        // Unwrap the dependency if it was resolved.
        return $defaultWrappedDependencyByType[0];
    }
}

if ($this->isNested) {
    $this->configureClusterFqn(
        initialQuestion: 'Is the parent resource in a cluster?',
        question: 'Which cluster is the parent resource in?',
    );
} else {
    $this->configureClusterFqn(
        initialQuestion: 'Would you like to create this resource in a cluster?',
        question: 'Which cluster would you like to create this resource in?',
    );
}

trait CanBeLiberatedFromContainerGrid
{
    protected bool | Closure $isLiberatedFromContainerGrid = false;

    public function liberatedFromContainerGrid(bool | Closure $condition = true): static
    {
        $this->isLiberatedFromContainerGrid = $condition;

        return $this;
    }

    public function isLiberatedFromContainerGrid(): bool
    {
        return (bool) $this->evaluate($this->isLiberatedFromContainerGrid);
    }
}

foreach ($mutatedAttributes as $key) {
    // We want to spin through all the mutated attributes for this model and call
    // the mutator for the attribute. We cache off every mutated attributes so
    // we don't have to constantly check on attributes that actually change.
    if (! array_key_exists($key, $attributes)) {
        continue;
    }

    // Next, we will call the mutator for this attribute so that we can get these
    // mutated attribute's actual values. After we finish mutating each of the
    // attributes we will return this final array of the mutated attributes.
    $attributes[$key] = $this->mutateAttributeForArray(
        $key, $attributes[$key]
    );
}

class SupportReleaseTokens extends ComponentHook
{
    public static function provide()
    {
        on('dehydrate', function ($component, $context) {
            $context->addMemo('release', ReleaseToken::generate($component));
        });

        // Verify the release token before verifying the snapshot checksum, as we don't want to trigger a checksum
        // failure if the release token doesn't match as there may be intentional changes in the snapshot...
        on('checksum.verify', function ($checksum, $snapshot) {
            ReleaseToken::verify($snapshot);
        });
    }
}

try {
    $callbackResult = $callback($this);
}

// If we catch an exception we'll rollback this transaction and try again if we
// are not out of attempts. If we are out of attempts we will just throw the
// exception back out, and let the developer handle an uncaught exception.
catch (Throwable $e) {
    $this->handleTransactionException(
        $e, $currentAttempt, $attempts
    );

    continue;
}

